const input = $input.all()[0].json;
const { service, operation, ...rest } = input;

// Parse any string values that look like JSON (AI passes arrays/objects as strings)
for (const key of Object.keys(rest)) {
  const val = rest[key];
  if (typeof val === 'string' && (val.startsWith('[') || val.startsWith('{'))) {
    try { rest[key] = JSON.parse(val); } catch (e) {}
  }
}

let parameters;
if (service === 'json-to-excel' && operation === 'create_multi_sheet') {
  // AI provides flat data array + sheetName; API needs nested sheets structure
  const rows = Array.isArray(rest.data) ? rest.data : [];
  const sheetName = rest.sheetName || 'Sheet1';
  const headers = rows.length > 0 ? Object.keys(rows[0]) : [];
  parameters = { sheets: { [sheetName]: { headers, rows } } };
} else {
  parameters = rest;
}

return [{ json: { service, operation, parameters } }];
